#!/usr/bin/env bash
# Regenerate per-(traceloop x python) lock files from .github/release-config.json.
# Each lock is a full `pip freeze` of (requirements.in + traceloop-sdk==<T>)
# resolved inside python:<X.Y>-slim on linux/amd64, matching the image build.
#
# NOTE: this RE-RESOLVES against live PyPI — it captures a point-in-time snapshot,
# so re-running it later can legitimately change the pins as PyPI moves. That is
# why it is a human-run, intentional step (see RELEASING.md). CI does NOT run this;
# it runs the hermetic `make check-locks` instead.
# AUTO-GENERATED lock files — do not hand-edit. Run: make lock
set -euo pipefail

HERE="$(cd "$(dirname "${BASH_SOURCE[0]}")/.." && pwd)"   # python-instrumentation-provider/
CONFIG="$HERE/../.github/release-config.json"
LOCK_DIR="$HERE/locks"
REQ_IN="$HERE/requirements.in"
# Match the Dockerfile's base image source (ECR mirror), not Docker Hub, to avoid
# anonymous pull-rate limits and resolver skew from a differently-bundled pip.
REGISTRY="public.ecr.aws/docker/library"

command -v jq >/dev/null || { echo "jq is required" >&2; exit 1; }
command -v docker >/dev/null || { echo "docker is required" >&2; exit 1; }
[ -f "$CONFIG" ] || { echo "release-config.json not found at $CONFIG" >&2; exit 1; }
[ -f "$REQ_IN" ] || { echo "requirements.in not found at $REQ_IN" >&2; exit 1; }

mkdir -p "$LOCK_DIR"

# Unique (traceloop_version, python_version) pairs across all AMP versions.
pairs="$(jq -r '.["python-instrumentation-provider"][]
  | .traceloop_version as $t
  | .python_versions[]
  | "\($t) \(.)"' "$CONFIG" | sort -u)"

[ -n "$pairs" ] || { echo "No (traceloop x python) pairs found in $CONFIG" >&2; exit 1; }

while read -r T PY; do
  [ -z "${T:-}" ] && continue
  out="$LOCK_DIR/traceloop-${T}-python${PY}.txt"
  echo "Locking traceloop-sdk==$T on python$PY -> ${out#"$HERE"/}"
  # No pipe inside the container: python:slim's /bin/sh is dash (no pipefail), so a
  # failing `pip list` in a pipe would be masked. Emit the raw freeze; sort in bash.
  # stderr is kept (only stdout is silenced) so a ResolutionImpossible is visible.
  raw="$(docker run --rm --platform linux/amd64 \
    -v "$REQ_IN:/tmp/requirements.in:ro" \
    "${REGISTRY}/python:${PY}-slim" \
    sh -c "pip install --no-cache-dir -q -r /tmp/requirements.in 'traceloop-sdk==${T}' --target /tmp/p >/dev/null && pip list --path /tmp/p --format=freeze")"
  {
    echo "# AUTO-GENERATED by 'make lock' from .github/release-config.json — DO NOT EDIT."
    echo "# Inputs: requirements.in + traceloop-sdk==${T}   (python ${PY}, linux/amd64)"
    printf '%s\n' "$raw" | sort
  } > "$out"
done <<< "$pairs"

echo "Done. Wrote locks to ${LOCK_DIR#"$HERE"/}/"
